	for(LL i = 1;i < st;i ++){

		dp[i][0] = dp[i - 1][0];

		for(LL j = 1;j <= 31;j ++){

			dp[i][j] = min(dp[i - 1][j],(1 + dp[i - 1][j - 1]) * (1 + s[i].a) + s[i].b);

